34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;43&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    v &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token builtin&#34;&gt;list&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;v&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;44&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    k &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token builtin&#34;&gt;list&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;k&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;45&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    n &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;10&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;46&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    res &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; decrypt&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;n&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; v&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; k&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;47&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;for&lt;/span&gt; r &lt;span class=&#34;token keyword&#34;&gt;in&lt;/span&gt; res&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;48&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token keyword&#34;&gt;print&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;r&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;to_bytes&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;4&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#39;little&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;decode&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; end&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#39;&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h1 id=&#34;vm_flutter&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#vm_flutter&#34;&gt;#&lt;/a&gt; vm_flutter&lt;/h1&gt;
&lt;p&gt;虽然这个 apk 是使用 flutter 编写的，但是其实在本题中 flutter 仅仅是纸老虎般的存在。&lt;/p&gt;
&lt;p&gt;在本题的题目描述中给出了两个提示，第一是对 flag 的加密算法有且只有一个 vm，第二是全部 vm 相关的函数都定义在 Java 层中，dart 层仅仅只是调用 java 层中定义的函数。所以根据这两个提示，就可以联想到使用 frida 等 hook 框架去 hook java 层中 vm 相关的函数，打印出虚拟指令来进行分析，如果可以想到这一点，那么这题就迎刃而解了。倘若使用 reflutter 等 flutter 逆向工具，那么将会在 dart 虚拟机中越陷越深：(&lt;/p&gt;
&lt;p&gt;在本题中，opcode 是在 dart 层被定义的，但是这其实无关紧要，因为 vm 相关的函数是在 java 层中定义的，我们对 vm 函数 hook 的过程其实就是对 opcode 的 “解读” 过程，通过 hook 的操作，我们就可以将 vm 对内部栈或内存的操作映射为可读的、可以理解的虚拟指令来进行分析。&lt;/p&gt;
&lt;p&gt;所以设计本题也是基于这种思想，使用目前安卓层面逆向难度非常高的 flutter 框架，来模拟类似 vmprotect 这类强壳 opcode 未知的场景，甚至在 vmprotect 中 opcode 会在间隔不定时间后随机变换。虽然我们不知道 opcode，但是万变不离其宗，vm 解析 opcode 之后最终要执行的操作是不会变的。&lt;/p&gt;
&lt;p&gt;获取 flag 的过程如下&lt;/p&gt;
&lt;p&gt;使用 jadx 反编译，发现方法名被混淆，但是进入 &lt;code&gt;com.dasctf.vm_flutter.vm_flutter.MainActivity&lt;/code&gt;  可以看到 vm 相关的字符串&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;/CBCTF-2023/image-20231024101207340.png&#34; alt=&#34;image-20231024101207340&#34; style=&#34;aspect-ratio:747 / 958;&#34;&gt;&lt;/p&gt;
&lt;p&gt;通过给 &lt;code&gt;c2&lt;/code&gt;  赋不同的值来调用 vm 中的函数&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;/CBCTF-2023/image-20231024101214972.png&#34; alt=&#34;image-20231024101214972&#34; style=&#34;aspect-ratio:672 / 748;&#34;&gt;&lt;/p&gt;
&lt;p&gt;根据字符串的提示，我们便知道了被混淆的 vm 的函数都是什么含义&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;/CBCTF-2023/image-20231024101220002.png&#34; alt=&#34;image-20231024101220002&#34; style=&#34;aspect-ratio:813 / 848;&#34;&gt;&lt;/p&gt;
&lt;p&gt;同时我们还在这里发现了最终的校验函数，可以推测最终的 flag 应该有 33 位&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;/CBCTF-2023/image-20231024101225270.png&#34; alt=&#34;image-20231024101225270&#34; style=&#34;aspect-ratio:1707 / 277;&#34;&gt;&lt;/p&gt;
&lt;p&gt;使用 frida hook vm 函数来获取 vm 指令&lt;/p&gt;
