&gt;&gt;&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;&amp;amp;&lt;/span&gt; I&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;##&lt;/span&gt;&lt;span class=&#34;token expression&#34;&gt;&lt;span class=&#34;token class-name&#34;&gt;INTERFACE&lt;/span&gt;&lt;span class=&#34;token double-colon punctuation&#34;&gt;::&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;getDefaultImpl&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;58&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token expression&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;                                                                   &lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;59&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token expression&#34;&gt;&lt;span class=&#34;token keyword&#34;&gt;return&lt;/span&gt; I&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;##&lt;/span&gt;&lt;span class=&#34;token expression&#34;&gt;INTERFACE&lt;span class=&#34;token double-colon punctuation&#34;&gt;::&lt;/span&gt;default_impl&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;                              &lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;60&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token expression&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;                                                                   &lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;61&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token expression&#34;&gt;I&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;##&lt;/span&gt;&lt;span class=&#34;token expression&#34;&gt;INTERFACE&lt;span class=&#34;token double-colon punctuation&#34;&gt;::&lt;/span&gt;I&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;##&lt;/span&gt;&lt;span class=&#34;token expression&#34;&gt;&lt;span class=&#34;token function&#34;&gt;INTERFACE&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;                                    &lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;62&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token expression&#34;&gt;I&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;##&lt;/span&gt;&lt;span class=&#34;token expression&#34;&gt;INTERFACE&lt;span class=&#34;token double-colon punctuation&#34;&gt;::&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;~&lt;/span&gt;I&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;##&lt;/span&gt;&lt;span class=&#34;token expression&#34;&gt;&lt;span class=&#34;token function&#34;&gt;INTERFACE&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;                                   &lt;/span&gt;\&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;我们将 &lt;code&gt;interface_cast&amp;lt;AidlServiceManager&amp;gt;(new BpBinder(0))&lt;/code&gt;  通过宏定义替换一下看的会更加清楚，在这里 &lt;code&gt;asInterface&lt;/code&gt;  将 &