t;        &lt;span class=&#34;token keyword&#34;&gt;if&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;intr &lt;span class=&#34;token operator&#34;&gt;==&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;nullptr&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;31&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            intr &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token double-colon punctuation&#34;&gt;::&lt;/span&gt;android&lt;span class=&#34;token double-colon punctuation&#34;&gt;::&lt;/span&gt;&lt;span class=&#34;token class-name&#34;&gt;sp&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;&amp;lt;&lt;/span&gt;BpServiceManager&lt;span class=&#34;token operator&#34;&gt;&gt;&lt;/span&gt;&lt;span class=&#34;token double-colon punctuation&#34;&gt;::&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;make&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;obj&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;32&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;33&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;34&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;return&lt;/span&gt; intr&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;35&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;36&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;std&lt;span class=&#34;token double-colon punctuation&#34;&gt;::&lt;/span&gt;unique_ptr&lt;span class=&#34;token operator&#34;&gt;&amp;lt;&lt;/span&gt;IServiceManager&lt;span class=&#34;token operator&#34;&gt;&gt;&lt;/span&gt; IServiceManager&lt;span class=&#34;token double-colon punctuation&#34;&gt;::&lt;/span&gt;default_impl&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;37&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;bool&lt;/span&gt; &lt;span class=&#34;token class-name&#34;&gt;IServiceManager&lt;/span&gt;&lt;span class=&#34;token double-colon punctuation&#34;&gt;::&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;setDefaultImpl&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;std&lt;span class=&#34;token double-colon punctuation&#34;&gt;::&lt;/span&gt;unique_ptr&lt;span class=&#34;token operator&#34;&gt;&amp;lt;&lt;/span&gt;IServiceManager&lt;span class=&#34;token operator&#34;&gt;&gt;&lt;/span&gt; impl&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;38&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;39&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token comment&#34;&gt;/* Only one user of this interface can use this function     */&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;40&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token comment&#34;&gt;/* at a time. This is a heuristic to detect if two different */&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;41&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token comment&#34;&gt;/* users in the same process use this function.              */&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;42&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token function&#34;&gt;assert&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;!&lt;/span&gt;IServiceManager&lt;span class=&#34;token double-colon punctuation&#34;&gt;::&lt;/span&gt;default_impl&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;43&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;if&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;impl&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;44&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        IServiceManager&lt;span class=&#34;token double-colon punctuation&#34;&gt;::&lt;/span&gt;default_impl &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; std&lt;span class=&#34;token double-colon punctuation&#34;&gt;::&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;move&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;impl&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;45&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;token boolean&#34;&gt;true&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;46&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;47&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;token boolean&#34;&gt;false&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;48&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;49&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;const&lt;/span&gt; std&lt;span class=&#34;token double-colon punctuation&#34;&gt;::&lt;/span&gt;unique_ptr&lt;span class=&#34;token operator&#34;&gt;&amp;lt;&lt;/span&gt;IServiceManager&lt;span class=&#34;token operator&#34;&gt;&gt;&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;&amp;amp;&lt;/span&gt; &lt;span class=&#34;token class-name&#34;&gt;IServiceManager&lt;/span&gt;&lt;span class=&#34;token double-colon punctuation&#34;&gt;::&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;getDefaultImpl&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;50&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;51&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;return&lt;/span&gt; IServiceManager&lt;span class=&#34;token double-colon punctuation&#34;&gt;::&lt;/span&gt;default_impl&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;52&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;53&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token class-name&#34;&gt;IServiceManager&lt;/span&gt;&lt;span class=&#34;token double-colon punctuation&#34;&gt;::&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;IServiceManager&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;54&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token class-name&#34;&gt;IServiceManager&lt;/span&gt;&lt;span class=&#34;token double-colon punctuation&#34;&gt;::&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;~&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;IServiceManager&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h2 id=&#34;总结-2&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#总结-2&#34;&gt;#&lt;/a&gt; 总结&lt;/h2&gt;
&lt;p&gt;&lt;img data-src=&#34;/android-binder/1595250-20211114151757336-739536801.png&#34; alt=&#34;img&#34; style=&#34;aspect-ratio:1194 / 499;&#34;&gt;&lt;/p&gt;
&lt;h1 id=&#34;server向servicemanager注册服务&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#server向servicemanager注册服务&#34;&gt;#&lt;/a&gt; Server 向 ServiceManager 注册服务&lt;/h1&gt;
&lt;p&gt;这里以 &lt;code&gt;MediaServer&lt;/code&gt;  为例来分析 Server 向 ServiceManager 注册服务的过程&lt;/p&gt;
&lt;figure class=&#34;highlight cpp&#34;&gt;&lt;figcaption data-lang=&#34;C++&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;//platform\frameworks\av\media\mediaserver\main_mediaserver.cpp&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;int&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;main&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token keyword&#34;&gt;int&lt;/span&gt; argc __unused&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;char&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;*&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;*&lt;/span&gt;argv __unused&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token function&#34;&gt;signal&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;SIGPIPE&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; SIG_IGN&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;	&lt;span class=&#34;token comment&#34;&gt;// 创建一个 ProcessState 实例，打开默认驱动 /dev/binder 并进行 mmap 内存映射&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;	&lt;span class=&#34;token comment&#34;&gt;// 此方法的详细分析请参见右侧目录 ServiceManager 的启动过程 -&gt;ProcessState::init&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;9&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    sp&lt;span class=&#34;token operator&#34;&gt;&amp;lt;&lt;/span&gt;ProcessState&lt;span class=&#34;token operator&#34;&gt;&gt;&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;proc&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token class-name&#34;&gt;ProcessState&lt;/span&gt;&lt;span class=&#34;token double-colon punctuation&#34;&gt;::&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;self&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;10&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;11&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;	&lt;span class=&#34;token comment&#34;&gt;// 客户端获取 ServiceManagerShim 对象&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;12&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;	&lt;span class=&#34;token comment&#34;&gt;// 此方法的详细分析请参见右侧目录 ServiceManager 的获取过程&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;13&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    sp&lt;span class=&#34;token operator&#34;&gt;&amp;lt;&lt;/span&gt;IServiceManager&lt;span class=&#34;token operator&#34;&gt;&gt;&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;sm&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;defaultServiceManager&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;14&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token function&#34;&gt;ALOGI&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;ServiceManager: %p&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; sm&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;get&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;15&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;16&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;	&lt;span class=&#34;token comment&#34;&gt;// 注册 media.player 服务&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;17&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token class-name&#34;&gt;MediaPlayerService&lt;/span&gt;&lt;span class=&#34;token double-colon punctuation&#34;&gt;::&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;instantiate&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;18&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token class-name&#34;&gt;ResourceManagerService&lt;/span&gt;&lt;span class=&#34;token double-colon punctuation&#34;&gt;::&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;instantiate&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;19&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token function&#34;&gt;registerExtensions&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;20&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token double-colon punctuation&#34;&gt;::&lt;/span&gt;android&lt;span class=&#34;token double-colon punctuation&#34;&gt;::&lt;/span&gt;hardware&lt;span class=&#34;token double-colon punctuation&#34;&gt;::&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;configureRpcThreadpool&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;16&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token boolean&#34;&gt;false&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;21&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;	&lt;span class=&#34;token comment&#34;&gt;// 启动线程池&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;22&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token class-name&#34;&gt;ProcessState&lt;/span&gt;&lt;span class=&#34;token double-colon punctuation&#34;&gt;::&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;self&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;-&gt;&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;startThreadPool&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;23&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;	&lt;span class=&#34;token comment&#34;&gt;// 将线程加入线程池&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;24&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token class-name&#34;&gt;IPCThreadState&lt;/span&gt;&lt;span class=&#34;token double-colon punctuation&#34;&gt;::&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;self&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;-&gt;&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;joinThreadPool&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;25&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token double-colon punctuation&#34;&gt;::&lt;/span&gt;android&lt;span class=&#34;token double-colon punctuation&#34;&gt;::&lt;/span&gt;hardware&lt;span class=&#34;token double-colon punctuation&#34;&gt;::&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;joinRpcThreadpool&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;26&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;&lt;strong&gt;MediaPlayerService::instantiate&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;这个函数的作用就是调用 defaultServiceManager 的 addService 方法来添加向 ServiceManager 注册服务&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-c++&#34;&gt;//platform\frameworks\av\media\libmediaplayerservice\MediaPlayerService.cpp
void MediaPlayerService::instantiate() &amp;#123;
    defaultServiceManager()-&amp;gt;addService(
        String16(&amp;quot;media.player&amp;quot;), new MediaPlayerService());
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;defaultservicemanager-addservice&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#defaultservicemanager-addservice&#34;&gt;#&lt;/a&gt; defaultServiceManager()-&amp;gt;addService&lt;/h2&gt;
&lt;pre&gt;&lt;code class=&#34;language-c++&#34;&gt;//platform\frameworks\native\libs\binder\IServiceManager.cpp
status_t ServiceManagerShim::addService(const String16&amp;amp; name, const sp&amp;lt;IBinder&amp;gt;&amp;amp; service,
                                        bool allowIsolated, int dumpsysPriority)
&amp;#123;
    Status status = mTheRealServiceManager-&amp;gt;addService(
        String8(name).c_str(), service, allowIsolated, dumpsysPriority);
    return status.exceptionCode();
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;这里使用了 &lt;code&gt;mTheRealServiceManager&lt;/code&gt;  中的 &lt;code&gt;addService&lt;/code&gt;  方法，那么 mTheRealServiceManager 是从哪里来的呢？&lt;/p&gt;
&lt;h2 id=&#34;mtherealservicemanager&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#mtherealservicemanager&#34;&gt;#&lt;/a&gt; mTheRealServiceManager&lt;/h2&gt;
&lt;pre&gt;&lt;code class=&#34;language-c++&#34;&gt;//platform\frameworks\native\libs\binder\IServiceManager.cpp
using AidlServiceManager = android::os::IServiceManager;
// From the old libbinder IServiceManager interface to IServiceManager.
class ServiceManagerShim : public IServiceManager
&amp;#123;
public:
    ...
private:
    sp&amp;lt;AidlServiceManager&amp;gt; mTheRealServiceManager;
&amp;#125;;
ServiceManagerShim::ServiceManagerShim(const sp&amp;lt;AidlServiceManager&amp;gt;&amp;amp; impl)
 : mTheRealServiceManager(impl)
&amp;#123;&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;从这段 ServiceManagerShim 类的声明中，我们可以清楚的看到 mTheRealServiceManager 是 &lt;code&gt;android::os::IServiceManager&lt;/code&gt;  类型的实例，并且在 ServiceManagerShim 实例化时赋值&lt;/p&gt;
&lt;p&gt;而在 &lt;strong&gt;ServiceManager 的获取过程&lt;/strong&gt; 中，我们知道 &lt;code&gt;ServiceManagerShim &lt;/code&gt; 是在 &lt;code&gt;defaultServiceManager()&lt;/code&gt;  中实例化的&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-c++&#34;&gt;//platform\frameworks\native\libs\binder\IServiceManager.cpp
sp&amp;lt;IServiceManager&amp;gt; defaultServiceManager()
&amp;#123;
    std::call_once(gSmOnce, []() &amp;#123;
        sp&amp;lt;AidlServiceManager&amp;gt; sm = nullptr;
        while (sm == nullptr) &amp;#123;
			//获取ServiceManager的BBinder所对应的BpBinder对象,
			//并将该对象通过interface_cast转换为AidlServiceManager
            sm = interface_cast&amp;lt;AidlServiceManager&amp;gt;(ProcessState::self()-&amp;gt;getContextObject(nullptr));
            if (sm == nullptr) &amp;#123;
                ALOGE(&amp;quot;Waiting 1s on context object on %s.&amp;quot;, ProcessState::self()-&amp;gt;getDriverName().c_str());
                sleep(1);
            &amp;#125;
        &amp;#125;
		//实例化ServiceManagerShim
        gDefaultServiceManager = sp&amp;lt;ServiceManagerShim&amp;gt;::make(sm);
    &amp;#125;);

    return gDefaultServiceManager;
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;所以说 &lt;code&gt;mTheRealServiceManager &lt;/code&gt; 其实是 &lt;code&gt;BpServiceManager(new BpBinder(0))&lt;/code&gt; , 注册服务的顺序为 &lt;code&gt;BpServiceManager--&amp;gt;BpBinder--&amp;gt;IPCThreadState--&amp;gt;ioctl&lt;/code&gt;&lt;/p&gt;
&lt;p&gt;而 &lt;code&gt;BpServiceManager&lt;/code&gt;  现在是由 AIDL 自动生成在框架编译完成之后的 out 目录中的&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;BpServiceManager::addService&lt;/strong&gt;&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-c++&#34;&gt;//platform/out/soong/.intermediates/frameworks/native/libs/binder/libbinder/android_arm_armv8-a_shared/gen/aidl/android/os/IServiceManager.cpp
namespace android &amp;#123;
namespace os &amp;#123;

BpServiceManager::BpServiceManager(const ::android::sp&amp;lt;::android::IBinder&amp;gt;&amp;amp; _aidl_impl)
    : BpInterface&amp;lt;IServiceManager&amp;gt;(_aidl_impl)&amp;#123;//_aidl_impl 就是 BpBinder(0) 实例
&amp;#125;
--------------------------------------------------
    ::android::binder::Status BpServiceManager::addService(const ::std::string&amp;amp; name, const ::android::sp&amp;lt;::android::IBinder&amp;gt;&amp;amp; service, bool allowIsolated, int32_t dumpPriority) &amp;#123;
  ::android::Parcel _aidl_data;
  _aidl_data.markForBinder(remoteStrong());//0、和 Rpc Binder有关
  ::android::Parcel _aidl_reply;
  ::android::status_t _aidl_ret_status = ::android::OK;
  ::android::binder::Status _aidl_status;
  //1、写 interface
  _aidl_ret_status = _aidl_data.writeInterfaceToken(getInterfaceDescriptor());
  if (((_aidl_ret_status) != (::android::OK))) &amp;#123;
    goto _aidl_error;
  &amp;#125;
  //2、写 name
  _aidl_ret_status = _aidl_data.writeUtf8AsUtf16(name);
  if (((_aidl_ret_status) != (::android::OK))) &amp;#123;
    goto _aidl_error;
  &amp;#125;
  //3、写 binder 对象
  _aidl_ret_status = _aidl_data.writeStrongBinder(service);
  if (((_aidl_ret_status) != (::android::OK))) &amp;#123;
    goto _aidl_error;
  &amp;#125;
  //4、写 allowIsolated
  _aidl_ret_status = _aidl_data.writeBool(allowIsolated);
  if (((_aidl_ret_status) != (::android::OK))) &amp;#123;
    goto _aidl_error;
  &amp;#125;
  //5、写 dumpPriority
  _aidl_ret_status = _aidl_data.writeInt32(dumpPriority);
  if (((_aidl_ret_status) != (::android::OK))) &amp;#123;
    goto _aidl_error;
  &amp;#125;
  //6、借助 BpBinder(0)#transact 来发起 Binder 通信
  _aidl_ret_status = remote()-&amp;gt;transact(BnServiceManager::TRANSACTION_addService, _aidl_data, &amp;amp;_aidl_reply, 0);
  if (UNLIKELY(_aidl_ret_status == ::android::UNKNOWN_TRANSACTION &amp;amp;&amp;amp; IServiceManager::getDefaultImpl())) &amp;#123;
     return IServiceManager::getDefaultImpl()-&amp;gt;addService(name, service, allowIsolated, dumpPriority);
  &amp;#125;
  if (((_aidl_ret_status) != (::android::OK))) &amp;#123;
    goto _aidl_error;
  &amp;#125;
  //7、如果有返回值就从这个 parcel 包里读
  _aidl_ret_status = _aidl_status.readFromParcel(_aidl_reply);
  if (((_aidl_ret_status) != (::android::OK))) &amp;#123;
    goto _aidl_error;
  &amp;#125;
  if (!_aidl_status.isOk()) &amp;#123;
    return _aidl_status;
  &amp;#125;
  _aidl_error:
  _aidl_status.setFromStatusT(_aidl_ret_status);
  return _aidl_status;
&amp;#125;

&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;这个过程主要是借助 BpBinder (0)#transact 来发起 Binder 通信，Binder 驱动根据 handle == 0 找到我们的 ServiceManager 进程，唤醒他开始处理请求。&lt;/p&gt;
&lt;p&gt;还记得在 &lt;strong&gt;ServiceManager 的启动过程&lt;/strong&gt; 中的那个 while 循环函数吗？BinderCallback 就是用来处理 Binder 驱动发送的 &lt;code&gt;BR_TRANSACTION&lt;/code&gt;  信号的&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-c++&#34;&gt;//platform\frameworks\native\cmds\servicemanager\main.cpp
int main(int argc, char** argv) &amp;#123;
    ...
	//准备looper
    sp&amp;lt;Looper&amp;gt; looper = Looper::prepare(false /*allowNonCallbacks*/);

	//监听BC_ENTER_LOOPER信号,收到该信号后回调处理binder调用
    BinderCallback::setupTo(looper);

	//监听客户端回调
    ClientCallbackCallback::setupTo(looper, manager);

	//阻塞等待和处理事件
    while(true) &amp;#123;
        looper-&amp;gt;pollAll(-1);
    &amp;#125;

    // should not be reached
    return EXIT_FAILURE;
&amp;#125;

&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;bindercallback&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#bindercallback&#34;&gt;#&lt;/a&gt; BinderCallback&lt;/h2&gt;
&lt;p&gt;&lt;code&gt;BinderCallback::handleEvent&lt;/code&gt;  调用了 &lt;code&gt;IPCThreadState::self()-&amp;gt;handlePolledCommands()&lt;/code&gt;  来处理命令&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-c++&#34;&gt;//platform\frameworks\native\cmds\servicemanager\main.cpp
class BinderCallback : public LooperCallback &amp;#123;
public:
    static sp&amp;lt;BinderCallback&amp;gt; setupTo(const sp&amp;lt;Looper&amp;gt;&amp;amp; looper) &amp;#123;
        sp&amp;lt;BinderCallback&amp;gt; cb = sp&amp;lt;BinderCallback&amp;gt;::make();

        int binder_fd = -1;
		//监听BC_ENTER_LOOPER信号
        IPCThreadState::self()-&amp;gt;setupPolling(&amp;amp;binder_fd);
        LOG_ALWAYS_FATAL_IF(binder_fd &amp;lt; 0, &amp;quot;Failed to setupPolling: %d&amp;quot;, binder_fd);

        int ret = looper-&amp;gt;addFd(binder_fd,
                                Looper::POLL_CALLBACK,
                                Looper::EVENT_INPUT,
                                cb,
                                nullptr /*data*/);
        LOG_ALWAYS_FATAL_IF(ret != 1, &amp;quot;Failed to add binder FD to Looper&amp;quot;);

        return cb;
    &amp;#125;

    int handleEvent(int /* fd */, int /* events */, void* /* data */) override &amp;#123;
        IPCThreadState::self()-&amp;gt;handlePolledCommands();
        return 1;  // Continue receiving callbacks.
    &amp;#125;
&amp;#125;;

&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;ipcthreadstatehandlepolledcommands&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#ipcthreadstatehandlepolledcommands&#34;&gt;#&lt;/a&gt; IPCThreadState::handlePolledCommands&lt;/h2&gt;
&lt;pre&gt;&lt;code class=&#34;language-c++&#34;&gt;//platform\frameworks\native\libs\binder\IPCThreadState.cpp
status_t IPCThreadState::handlePolledCommands()
&amp;#123;
    status_t result;

    do &amp;#123;
        //获取并执行命令
        result = getAndExecuteCommand();
    &amp;#125; while (mIn.dataPosition() &amp;lt; mIn.dataSize());

    processPendingDerefs();
    flushCommands();
    return result;
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;ipcthreadstategetandexecutecommand&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#ipcthreadstategetandexecutecommand&#34;&gt;#&lt;/a&gt; IPCThreadState::getAndExecuteCommand&lt;/h2&gt;
&lt;pre&gt;&lt;code class=&#34;language-c++&#34;&gt;//platform\frameworks\native\libs\binder\IPCThreadState.cpp
status_t IPCThreadState::getAndExecuteCommand()
&amp;#123;
    status_t result;
    int32_t cmd;

	//和binder驱动交流,获取或传输数据
    result = talkWithDriver();
    if (result &amp;gt;= NO_ERROR) &amp;#123;
        size_t IN = mIn.dataAvail();
        if (IN &amp;lt; sizeof(int32_t)) return result;
		//读取命令
        cmd = mIn.readInt32();
        IF_LOG_COMMANDS() &amp;#123;
            alog &amp;lt;&amp;lt; &amp;quot;Processing top-level Command: &amp;quot;
                 &amp;lt;&amp;lt; getReturnString(cmd) &amp;lt;&amp;lt; endl;
        &amp;#125;

        pthread_mutex_lock(&amp;amp;mProcess-&amp;gt;mThreadCountLock);
        mProcess-&amp;gt;mExecutingThreadsCount++;
        if (mProcess-&amp;gt;mExecutingThreadsCount &amp;gt;= mProcess-&amp;gt;mMaxThreads &amp;amp;&amp;amp;
                mProcess-&amp;gt;mStarvationStartTimeMs == 0) &amp;#123;
            mProcess-&amp;gt;mStarvationStartTimeMs = uptimeMillis();
        &amp;#125;
        pthread_mutex_unlock(&amp;amp;mProcess-&amp;gt;mThreadCountLock);

		//解析并执行命令
        result = executeCommand(cmd);

        pthread_mutex_lock(&amp;amp;mProcess-&amp;gt;mThreadCountLock);
        mProcess-&amp;gt;mExecutingThreadsCount--;
        if (mProcess-&amp;gt;mExecutingThreadsCount &amp;lt; mProcess-&amp;gt;mMaxThreads &amp;amp;&amp;amp;
                mProcess-&amp;gt;mStarvationStartTimeMs != 0) &amp;#123;
            int64_t starvationTimeMs = uptimeMillis() - mProcess-&amp;gt;mStarvationStartTimeMs;
            if (starvationTimeMs &amp;gt; 100) &amp;#123;
                ALOGE(&amp;quot;binder thread pool (%zu threads) starved for %&amp;quot; PRId64 &amp;quot; ms&amp;quot;,
                      mProcess-&amp;gt;mMaxThreads, starvationTimeMs);
            &amp;#125;
            mProcess-&amp;gt;mStarvationStartTimeMs = 0;
        &amp;#125;

        // Cond broadcast can be expensive, so don&#39;t send it every time a binder
        // call is processed. b/168806193
        if (mProcess-&amp;gt;mWaitingForThreads &amp;gt; 0) &amp;#123;
            pthread_cond_broadcast(&amp;amp;mProcess-&amp;gt;mThreadCountDecrement);
        &amp;#125;
        pthread_mutex_unlock(&amp;amp;mProcess-&amp;gt;mThreadCountLock);
    &amp;#125;

    return result;
&amp;#125;

&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;ipcthreadstateexecutecommand&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#ipcthreadstateexecutecommand&#34;&gt;#&lt;/a&gt; IPCThreadState::executeCommand&lt;/h2&gt;
&lt;pre&gt;&lt;code class=&#34;language-c++&#34;&gt;//platform\frameworks\native\libs\binder\IPCThreadState.cpp
status_t IPCThreadState::executeCommand(int32_t cmd)
&amp;#123;
	switch ((uint32_t)cmd) &amp;#123;
		case BR_TRANSACTION:
        &amp;#123;	//因为目的端 SM 所以 tr.target.ptr 为 0
        	if (tr.target.ptr) &amp;#123;
        	...
        	&amp;#125;else &amp;#123;//开始业务分发
        	    error = the_context_object-&amp;gt;transact(tr.code, buffer, &amp;amp;reply, tr.flags);
        	&amp;#125;

&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;在&lt;strong&gt; ServiceManager 的启动过程&lt;/strong&gt; 这节的内容中，我们让 ServiceManager 成为了整个 binder IPC 通信中的上下文管理者，并将其存储在全局变量 &lt;code&gt;the_context_object&lt;/code&gt;  中&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-c++&#34;&gt;//platform\frameworks\native\cmds\servicemanager\main.cpp
sp&amp;lt;BBinder&amp;gt; the_context_object;

void IPCThreadState::setTheContextObject(const sp&amp;lt;BBinder&amp;gt;&amp;amp; obj)
&amp;#123;
    the_context_object = obj;
&amp;#125;

int main(int argc, char** argv) &amp;#123;
    ...
	//将&amp;quot;manager&amp;quot;服务作为服务端Bbinder对象
    IPCThreadState::self()-&amp;gt;setTheContextObject(manager);
	//向binder驱动发送ioctl BINDER_SET_CONTEXT_MGR_EXT信号,将servicemanager
	//在ProcessState::initWithDriver中打开驱动设备/dev/driver所返回的文件描述符句柄
	//作为整个binder IPC通信中的上下文管理者
    ps-&amp;gt;becomeContextManager();
	...
&amp;#125;

&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;所以 &lt;code&gt;the_context_object-&amp;gt;transact()&lt;/code&gt;  调用就走到  &lt;code&gt;BBinder&lt;/code&gt;  的 transact&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-c++&#34;&gt;//platform\frameworks\native\libs\binder\Binder.cpp

// NOLINTNEXTLINE(google-default-arguments)
status_t BBinder::transact(
    uint32_t code, const Parcel&amp;amp; data, Parcel* reply, uint32_t flags)
&amp;#123;
    data.setDataPosition(0);

    if (reply != nullptr &amp;amp;&amp;amp; (flags &amp;amp; FLAG_CLEAR_BUF)) &amp;#123;
        reply-&amp;gt;markSensitive();
    &amp;#125;

    status_t err = NO_ERROR;
    switch (code) &amp;#123;
        case PING_TRANSACTION:
            err = pingBinder();
            break;
        case EXTENSION_TRANSACTION:
            err = reply-&amp;gt;writeStrongBinder(getExtension());
            break;
        case DEBUG_PID_TRANSACTION:
            err = reply-&amp;gt;writeInt32(getDebugPid());
            break;
        default:
            err = onTransact(code, data, reply, flags);
            break;
    &amp;#125;

    // In case this is being transacted on in the same process.
    if (reply != nullptr) &amp;#123;
        reply-&amp;gt;setDataPosition(0);
    &amp;#125;

    return err;
&amp;#125;

&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;然后回到了这个 AIDL 自动生成的 IServiceManager.cpp 中 BnServiceManager 的 onTransact () 方法里&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-c++&#34;&gt;//platform/out/soong/.intermediates/frameworks/native/libs/binder/libbinder/android_arm_armv8-a_shared/gen/aidl/android/os/IServiceManager.cpp

::android::status_t BnServiceManager::onTransact(uint32_t _aidl_code, const ::android::Parcel&amp;amp; _aidl_data, ::android::Parcel* _aidl_reply, uint32_t _aidl_flags) &amp;#123;
  ::android::status_t _aidl_ret_status = ::android::OK;
  switch (_aidl_code) &amp;#123;
  case BnServiceManager::TRANSACTION_addService:
  &amp;#123;
    ::std::string in_name;
    ::android::sp&amp;lt;::android::IBinder&amp;gt; in_service;
    bool in_allowIsolated;
    int32_t in_dumpPriority;
    //检查 interface
    if (!(_aidl_data.checkInterface(this))) &amp;#123;
      _aidl_ret_status = ::android::BAD_TYPE;
      break;
    &amp;#125;
    //读 name
    _aidl_ret_status = _aidl_data.readUtf8FromUtf16(&amp;amp;in_name);
    if (((_aidl_ret_status) != (::android::OK))) &amp;#123;
      break;
    &amp;#125;
    //读 binder
    _aidl_ret_status = _aidl_data.readStrongBinder(&amp;amp;in_service);
    if (((_aidl_ret_status) != (::android::OK))) &amp;#123;
      break;
    &amp;#125;
    //读 in_allowIsolated
    _aidl_ret_status = _aidl_data.readBool(&amp;amp;in_allowIsolated);
    if (((_aidl_ret_status) != (::android::OK))) &amp;#123;
      break;
    &amp;#125;
    //读 in_dumpPriority
    _aidl_ret_status = _aidl_data.readInt32(&amp;amp;in_dumpPriority);
    if (((_aidl_ret_status) != (::android::OK))) &amp;#123;
      break;
    &amp;#125;
    //调用真正的 ServiceManager.cpp 中的实现
    ::android::binder::Status _aidl_status(addService(in_name, in_service, in_allowIsolated, in_dumpPriority));
    //如果有返回写返回到 _aidl_reply
    _aidl_ret_status = _aidl_status.writeToParcel(_aidl_reply);
    if (((_aidl_ret_status) != (::android::OK))) &amp;#123;
      break;
    &amp;#125;
    if (!_aidl_status.isOk()) &amp;#123;
      break;
    &amp;#125;
  &amp;#125;

&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;这里是和 Bp 端是对称的操作，下一步走到 ServiceManager.cpp::addService 方法&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-c++&#34;&gt;//platform\frameworks\native\cmds\servicemanager\ServiceManager.cpp

Status ServiceManager::addService(const std::string&amp;amp; name, const sp&amp;lt;IBinder&amp;gt;&amp;amp; binder, bool allowIsolated, int32_t dumpPriority) &amp;#123;
    auto ctx = mAccess-&amp;gt;getCallingContext();

    // apps cannot add services
    if (multiuser_get_app_id(ctx.uid) &amp;gt;= AID_APP) &amp;#123;
        return Status::fromExceptionCode(Status::EX_SECURITY);
    &amp;#125;

    if (!mAccess-&amp;gt;canAdd(ctx, name)) &amp;#123;
        return Status::fromExceptionCode(Status::EX_SECURITY);
    &amp;#125;

    if (binder == nullptr) &amp;#123;
        return Status::fromExceptionCode(Status::EX_ILLEGAL_ARGUMENT);
    &amp;#125;

	//检验Service名称的合法性,名称长度要求大于0并小于等于127
	//字符仅包括[a-z][A-Z][0-9]_-./
    if (!isValidServiceName(name)) &amp;#123;
        LOG(ERROR) &amp;lt;&amp;lt; &amp;quot;Invalid service name: &amp;quot; &amp;lt;&amp;lt; name;
        return Status::fromExceptionCode(Status::EX_ILLEGAL_ARGUMENT);
    &amp;#125;

#ifndef VENDORSERVICEMANAGER
    if (!meetsDeclarationRequirements(binder, name)) &amp;#123;
        // already logged
        return Status::fromExceptionCode(Status::EX_ILLEGAL_ARGUMENT);
    &amp;#125;
#endif  // !VENDORSERVICEMANAGER

    // implicitly unlinked when the binder is removed
    // 为binder对象设置死亡代理
    /*
	在和service进行交互时，service返回一个Binder对象。
	Binder是工作在service端，如果，由于某种原因，服务端出现故障而死亡，
	那么该返回的Binder对象也将消失，这时，如果我们在客户端在使用Binder对象
	进行某些函数调用将会出现错误。为了避免该情况的发生，我们可以为
	Binder对象设置死亡代理(linkToDeath)。当出现和服务端连接发生故障时，
	系统将自动调用死亡代理函数binderDied()。
	*/
    if (binder-&amp;gt;remoteBinder() != nullptr &amp;amp;&amp;amp;
        binder-&amp;gt;linkToDeath(sp&amp;lt;ServiceManager&amp;gt;::fromExisting(this)) != OK) &amp;#123;
        LOG(ERROR) &amp;lt;&amp;lt; &amp;quot;Could not linkToDeath when adding &amp;quot; &amp;lt;&amp;lt; name;
        return Status::fromExceptionCode(Status::EX_ILLEGAL_STATE);
    &amp;#125;

    // Overwrite the old service if it exists
    //添加服务,以name作为索引值,使用binder作为参数实例化Service对象
    mNameToService[name] = Service &amp;#123;
        .binder = binder,
        .allowIsolated = allowIsolated,
        .dumpPriority = dumpPriority,
        .debugPid = ctx.debugPid,
    &amp;#125;;


	/*检查服务注册的合法性,包括
	1.服务是否存在
	2.该服务是否是服务端注册的
	3.是否有同名服务存在
	4.为该服务注册的死亡代理是否成功
	*/
    auto it = mNameToRegistrationCallback.find(name);
    if (it != mNameToRegistrationCallback.end()) &amp;#123;
        for (const sp&amp;lt;IServiceCallback&amp;gt;&amp;amp; cb : it-&amp;gt;second) &amp;#123;
            mNameToService[name].guaranteeClient = true;
            // permission checked in registerForNotifications
            cb-&amp;gt;onRegistration(name, binder);
        &amp;#125;
    &amp;#125;

    return Status::ok();
&amp;#125;

&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;总结-3&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#总结-3&#34;&gt;#&lt;/a&gt; 总结&lt;/h2&gt;
&lt;p&gt;Server 想要向 ServiceManager 注册服务，首先通过 &lt;code&gt;defaultServiceManager&lt;/code&gt;  获取到一个 Service Manager 的代理对象，然后再调用它的成员函数 &lt;code&gt;addService&lt;/code&gt;  将该 Service 组件注册到 Service Manager 中，该代理对象通过向 Binder 驱动设备发送 &lt;code&gt;BC_TRANSACTION&lt;/code&gt;  信号和 &lt;code&gt;Service Manager&lt;/code&gt;  通信，在 &lt;code&gt;Service Manager&lt;/code&gt;  启动之后会进入一个阻塞的无限循环， &lt;code&gt;Service Manager&lt;/code&gt;  通过 &lt;code&gt;BinderCallback&lt;/code&gt;  回调函数处理 Binder 驱动设备返回的 &lt;code&gt;BR_TRANSACTION&lt;/code&gt; , 调用 BBinder 的 transact 方法，这个方法将会把我们引到 BnServiceManager 的 onTransact () 方法，终于这个方法将我们带到了真正添加服务的方法&lt;strong&gt; ServiceManager.cpp::addService&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;/android-binder/1595250-20211114151811263-2017459210.png&#34; alt=&#34;img&#34; style=&#34;aspect-ratio:1241 / 601;&#34;&gt;&lt;/p&gt;
&lt;h1 id=&#34;client向servicemanager获取服务&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#client向servicemanager获取服务&#34;&gt;#&lt;/a&gt; Client 向 ServiceManager 获取服务&lt;/h1&gt;
&lt;h1 id=&#34;参考资料&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#参考资料&#34;&gt;#&lt;/a&gt; 参考资料&lt;/h1&gt;
&lt;ul&gt;
&lt;li&gt;&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9naXR5dWFuLmNvbS8yMDE0LzAxLzAxL2JpbmRlci1nYWlzaHUv&#34;&gt;gityuan 大佬的 Binder 系列&lt;/span&gt;&lt;/li&gt;
&lt;li&gt;&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9kb2MueW9ueW91Y2xvdWQuY29tL2RvYy93aWtpL3Byb2plY3QvZGVlcC1hbmRyb2lkLXYxL2JpbmRlci5odG1sIzA3ZjcwNTE0YmIzODhkYmUyYTFmYzJjYmU3ZGNmZGM4&#34;&gt;第 6 章 深入理解 Binder&lt;/span&gt;&lt;/li&gt;
&lt;li&gt;&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly93d3cuY25ibG9ncy5jb20vd2FuZ2hvbmd6aHUvcC8xNTU1MTk3OC5odG1s&#34;&gt;Android 12 系统源码分析 | Native Binder 代码变迁 &lt;/span&gt;&lt;/li&gt;
&lt;li&gt;&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly93d3cuY25ibG9ncy5jb20vaW5ub3N0L2FyY2hpdmUvMjAxMS8wMS8wOS8xOTMxNDU2Lmh0bWw=&#34;&gt;Android 深入浅出之 Binder 机制 &lt;/span&gt;&lt;/li&gt;
&lt;li&gt;&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly93d3cuY25ibG9ncy5jb20vaGVsbG9raXR0eTIvcC8xNTA4ODI2NS5odG1s&#34;&gt;理解 Android Binder 机制 (2/3)：C++ 层&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;

 &lt;h1 id=&#34;安卓系统源码下载&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#安卓系统源码下载&#34;&gt;#&lt;/a&gt; 安卓系统源码下载&lt;/h1&gt;
&lt;div class=&#34;note warning&#34;&gt;
&lt;p&gt;想要下载安卓系统全部的源码，请必须预留 150G-200G 的空间，并保持 VPN 连接稳定，否则将导致下载失败并从头下载！&lt;/p&gt;
&lt;/div&gt;
&lt;h2 id=&#34;查看android版本&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#查看android版本&#34;&gt;#&lt;/a&gt; 查看 android 版本&lt;/h2&gt;
&lt;p&gt;进入&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9zb3VyY2UuYW5kcm9pZC5jb20vZG9jcy9zZXR1cC9hYm91dC9idWlsZC1udW1iZXJzP2hsPXpoLWNu&#34;&gt;代号，标记和 build 号&lt;/span&gt;来查看安卓系统的版本&lt;/p&gt;
&lt;p&gt;如果是预装的系统，那么 kernel 版本和系统版本是有对应关系的，例如我给 pixel3 刷入的系统为 &lt;code&gt;blueline-sp1a.210812.016.c2-factory-fa981d87&lt;/code&gt; , 那么在上面提到的网址内找到该安卓系统该 &lt;code&gt;build ID&lt;/code&gt;  所对应的安卓系统版本 &lt;code&gt;android-12.0.0_r34&lt;/code&gt;  如图所示&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;/android-source-code/image-20231010095645706.png&#34; alt=&#34;image-20231010095645706&#34; style=&#34;aspect-ratio:1920 / 1078;&#34;&gt;&lt;/p&gt;
&lt;h2 id=&#34;下载&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#下载&#34;&gt;#&lt;/a&gt; 下载&lt;/h2&gt;
&lt;p&gt;关于环境的配置请参阅&lt;a href=&#34;oacia.cc/rwprocmem33-usage&#34;&gt;这篇文章&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;输入如下命令来进行安卓系统源码下载，分支就选择我们之前查找到的那个分支&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;figcaption data-lang=&#34;Bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;mkdir&lt;/span&gt; android-platform &lt;span class=&#34;token operator&#34;&gt;&amp;amp;&amp;amp;&lt;/span&gt; &lt;span class=&#34;token builtin class-name&#34;&gt;cd&lt;/span&gt; android-platform&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;repo init &lt;span class=&#34;token parameter variable&#34;&gt;-u&lt;/span&gt; https://android.googlesource.com/platform/manifest &lt;span class=&#34;token parameter variable&#34;&gt;-b&lt;/span&gt; android-12.0.0_r34 &lt;span class=&#34;token parameter variable&#34;&gt;--depth&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;1&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;repo &lt;span class=&#34;token function&#34;&gt;sync&lt;/span&gt; &lt;span class=&#34;token parameter variable&#34;&gt;-j4&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h1 id=&#34;安卓系统源码按需下载&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#安卓系统源码按需下载&#34;&gt;#&lt;/a&gt; 安卓系统源码按需下载&lt;/h1&gt;
&lt;p&gt;有的时候，我们并不需要高达一百多 G 的源码，而仅仅想要看我们感兴趣的部分的源码，这个时候我们可以进行按需下载&lt;/p&gt;
&lt;p&gt;来到&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9hbmRyb2lkLmdvb2dsZXNvdXJjZS5jb20vcGxhdGZvcm0v&#34;&gt; Google git android platform&lt;/span&gt;, 例如我们想要看 &lt;code&gt;frameworks/base&lt;/code&gt;  这部分的源码，那我们就全局搜索并将进入这里&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;/android-source-code/image-20231010100305043.png&#34; alt=&#34;image-20231010100305043&#34; style=&#34;aspect-ratio:1920 / 1078;&#34;&gt;&lt;/p&gt;
&lt;p&gt;在这里上面有提示我们可以用 &lt;code&gt;git clone&lt;/code&gt;  命令来进行下载&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;/android-source-code/image-20231010100409464.png&#34; alt=&#34;image-20231010100409464&#34; style=&#34;aspect-ratio:1920 / 1078;&#34;&gt;&lt;/p&gt;
&lt;p&gt;当然直接输入命令是没有问题的，但是我们也可以去筛选我们想要的分支来进行下载&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;figcaption data-lang=&#34;Bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;git&lt;/span&gt; clone https://android.googlesource.com/platform/frameworks/base &lt;span class=&#34;token parameter variable&#34;&gt;-b&lt;/span&gt; android-12.0.0_r34 &lt;span class=&#34;token parameter variable&#34;&gt;--depth&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;1&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h1 id=&#34;安卓系统源码目录结构&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#安卓系统源码目录结构&#34;&gt;#&lt;/a&gt; 安卓系统源码目录结构&lt;/h1&gt;
&lt;h2 id=&#34;根目录总览&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#根目录总览&#34;&gt;#&lt;/a&gt; 根目录总览&lt;/h2&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;figcaption data-lang=&#34;Bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token operator&#34;&gt;|&lt;/span&gt;-- Makefile&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token operator&#34;&gt;|&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token operator&#34;&gt;|&lt;/span&gt;-- art（Android Runtime，一种App运行模式，区别于传统的Dalvik虚拟机，旨在提高Android系统的流畅性）&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token operator&#34;&gt;|&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token operator&#34;&gt;|&lt;/span&gt;-- bionic               （bionic C库）&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token operator&#34;&gt;|&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token operator&#34;&gt;|&lt;/span&gt;-- bootable             （启动引导相关代码）&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token operator&#34;&gt;|&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;9&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token operator&#34;&gt;|&lt;/span&gt;-- build                （存放系统编译规则及generic等基础开发包配置）&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;10&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token operator&#34;&gt;|&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;11&#34;&gt