n class=&#34;token directive keyword&#34;&gt;include&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&amp;lt;sys/socket.h&gt;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token macro property&#34;&gt;&lt;span class=&#34;token directive-hash&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;token directive keyword&#34;&gt;include&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&amp;lt;sys/un.h&gt;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token macro property&#34;&gt;&lt;span class=&#34;token directive-hash&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;token directive keyword&#34;&gt;include&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&amp;lt;string.h&gt;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;9&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token macro property&#34;&gt;&lt;span class=&#34;token directive-hash&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;token directive keyword&#34;&gt;include&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&amp;lt;arpa/inet.h&gt;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;10&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token macro property&#34;&gt;&lt;span class=&#34;token directive-hash&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;token directive keyword&#34;&gt;include&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&amp;lt;netinet/in.h&gt;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;11&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token macro property&#34;&gt;&lt;span class=&#34;token directive-hash&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;token directive keyword&#34;&gt;include&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&amp;lt;netdb.h&gt;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;12&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;13&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;int&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;main&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;14&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;	&lt;span class=&#34;token keyword&#34;&gt;int&lt;/span&gt; client_fd &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;0&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;15&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;	&lt;span class=&#34;token keyword&#34;&gt;struct&lt;/span&gt; &lt;span class=&#34;token class-name&#34;&gt;sockaddr_in&lt;/span&gt; server_addr&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;16&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;	server_addr&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;sin_family &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; AF_INET&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;17&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;	server_addr&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;sin_addr&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;s_addr &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;inet_addr&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;127.0.0.1&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;18&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;	server_addr&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;sin_port &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;htons&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;8888&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;19&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;20&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;	&lt;span class=&#34;token comment&#34;&gt;//create socket&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;21&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;	client_fd &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;socket&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;AF_INET&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; SOCK_DGRAM&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;0&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;22&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;23&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;	&lt;span class=&#34;token comment&#34;&gt;//send data&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;24&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;char&lt;/span&gt; send_msg&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#34;hello server&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;25&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token function&#34;&gt;sendto&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;client_fd&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; send_msg&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;sizeof&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;send_msg&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;0&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token keyword&#34;&gt;struct&lt;/span&gt; &lt;span class=&#34;token class-name&#34;&gt;sockaddr&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;*&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;&amp;amp;&lt;/span&gt;server_addr&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;sizeof&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;server_addr&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;26&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token function&#34;&gt;printf&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;Write \&#34;hello server\&#34; to server ok.\n&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;27&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;28&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;	&lt;span class=&#34;token comment&#34;&gt;//close fd&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;29&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;	&lt;span class=&#34;token function&#34;&gt;close&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;client_fd&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;30&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;	&lt;span class=&#34;token keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;0&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;31&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h1 id=&#34;参考资料&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#参考资料&#34;&gt;#&lt;/a&gt; 参考资料&lt;/h1&gt;
&lt;ul&gt;
&lt;li&gt;&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9kbG9ubmcuY29tL3Bvc3RzL3RjcF91ZHA=&#34;&gt;Linux 高级编程 - Socket 编程基础（TCP，UDP）&lt;/span&gt;&lt;/li&gt;
&lt;li&gt;&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9saXNoaXdlbjQuZ2l0aHViLmlvL25ldHdvcmsvc29ja2V0LWludGVyZmFjZS1hbmQtbmV0d29yay1wcm90b2NvbA==&#34;&gt;socket 接口的网络协议无关性&lt;/span&gt;&lt;/li&gt;
&lt;li&gt;&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly96aHVhbmxhbi56aGlodS5jb20vcC80NjkyOTQ4Mzc=&#34;&gt;一文搞懂 Linux 的 Socket 编程原理 (含实例解析)&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;

 &lt;h1 id=&#34;前言&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#前言&#34;&gt;#&lt;/a&gt; 前言&lt;/h1&gt;
&lt;blockquote&gt;
&lt;p&gt;在今年三月份的时候，我参加了腾讯游戏安全技术竞赛，到现在差不多快过去半年了，当时做这道安卓初赛题目时，也是卡在开头就毫无头绪了，而后看到看雪上的三位大佬&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9iYnMua2FueHVlLmNvbS91c2VyLWhvbWUtODg4NTU4Lmh0bQ==&#34;&gt; |_|sher 师傅&lt;/span&gt;，&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9iYnMua2FueHVlLmNvbS91c2VyLWhvbWUtODMxNTI2Lmh0bQ==&#34;&gt;juice4fun 师傅&lt;/span&gt;和&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9iYnMua2FueHVlLmNvbS91c2VyLWhvbWUtODg3Njc2Lmh0bQ==&#34;&gt; fallw1nd 师傅&lt;/span&gt;都分享了他们做这道题目时的解题过程，也是让我重拾了做出这道安卓初赛题的信心，因为需要分心在学习和其他事情上，所以从三月份到七月份也是陆陆续续复现了五个月，一路上走走停停&lt;/p&gt;
&lt;p&gt;终于在八月份，我难能可贵的获得了整整一个月的充裕时间，这也让我可以好好去钻研这道对我来说难度极大的安卓题目了，解题的过程中基本上把我能想到的安卓逆向工具用了个遍，每当我在解题的过程中遇到瓶颈时，我总会把这三位大佬的 writeup 打开来反复观摩研究思考为什么要这样做，怎么做效果会更好&lt;/p&gt;
&lt;p&gt;直到注册机写完之后纵观整个解题过程，真的是学到了很多&lt;/p&gt;
&lt;p&gt;il2CppDumper 是分析 unity 游戏的基础，能有好的开头全靠站在巨人的肩膀上&lt;/p&gt;
&lt;p&gt;运行时解密 so 文件，让我首次尝试去手工修复 dump 下来的 so&lt;/p&gt;
&lt;p&gt;libsec2023.so 中的反调试让我学会使用在安卓手机中断下硬件断点的工具 rwProcMem33, 也开始第一次编译安卓内核，经历了两三个不眠之夜&lt;/p&gt;
&lt;p&gt;第一眼见到 CSEL-BR 和 CSET-BR 结构的花指令让我毫无头绪，也让我开始思考 frida-stalker 与 unicorn 的区别所在，最终我选择使用 frida-stalker 辅助分析，IDApython 批量去花的方法，效果很好&lt;/p&gt;
&lt;p&gt;BlackObfuscator 混淆让我想起了被 ollvm 的控制流平坦化支配的恐惧，一筹莫展之际，这个月最新的工具 Jeb5.1 竟然能完美去除 BlackObfuscator 混淆，着实让我惊喜不已&lt;/p&gt;
&lt;p&gt;在探索 vm 的过程，我也慢慢的摸索出了 vm 题型的解题方法，或许未来遇到 vm 我也能游刃有余了&lt;/p&gt;
&lt;p&gt;前言写的有点长了，也算是我在这半年对于这道安卓题的感悟吧哈哈，虽然是安卓方向初赛题，但是对我整个安卓逆向的学习过程意义非凡，这篇文章我也写的尽可能的详细，前后的思维也尽量避免跳跃，每一步的操作基本上都是有据可依的，为之后也同样想要复现这道赛题的朋友尽一点绵薄之力&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;题目可以在腾讯游戏安全竞赛官网下载 &lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9nc2xhYi5xcS5jb20vaHRtbC9jb21wZXRpdGlvbi8yMDIzL2RvYy8lRTUlQUUlODklRTUlOEQlOTMlRTUlQUUlQTIlRTYlODglQjclRTclQUIlQUYlRTUlQUUlODklRTUlODUlQTgtJUU1JTg4JTlEJUU4JUI1JTlCJUU5JUEyJTk4JUU3JTlCJUFFLnppcA==&#34;&gt;下载链接&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;我在 github 里面也存了一份上去 &lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9vYWNpYS5naXRodWIuaW8vc2VjLTIwMjMvJUU1JUFFJTg5JUU1JThEJTkzJUU1JUFFJUEyJUU2JTg4JUI3JUU3JUFCJUFGJUU1JUFFJTg5JUU1JTg1JUE4LSVFNSU4OCU5RCVFOCVCNSU5QiVFOSVBMiU5OCVFNyU5QiVBRS56aXA=&#34;&gt;备用下载链接&lt;/span&gt;&lt;/p&gt;
&lt;h1 id=&#34;初探apk&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#初探apk&#34;&gt;#&lt;/a&gt; 初探 apk&lt;/h1&gt;
&lt;p&gt;首先我们通过 jadx 反编译 &lt;code&gt;mouse_pre.aligned.signed.apk&lt;/code&gt; , 通过查看 &lt;code&gt;AndroidManifest.xml&lt;/code&gt;  可以知道下列关键信息&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;包名:  &lt;code&gt;com.com.sec2023.rocketmouse.mouse&lt;/code&gt;&lt;/li&gt;
&lt;li&gt;入口:  &lt;code&gt;com.unity3d.player.UnityPlayerActivity&lt;/code&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;解压该 apk, 通过查看 &lt;code&gt;lib&lt;/code&gt;  文件夹内的内容，我们发现了 &lt;code&gt;libil2cpp.so&lt;/code&gt;&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;/sec-2023/image-20230407124030376.png&#34; alt=&#34;image-20230407124030376&#34; style=&#34;aspect-ratio:1034 / 254;&#34;&gt;&lt;/p&gt;
&lt;h1 id=&#34;尝试使用il2cppdumper获取符号信息&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#尝试使用il2cppdumper获取符号信息&#34;&gt;#&lt;/a&gt; 尝试使用 Il2CppDumper 获取符号信息&lt;/h1&gt;
&lt;p&gt;我们使用&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9naXRodWIuY29tL1BlcmZhcmUvSWwyQ3BwRHVtcGVy&#34;&gt; Il2CppDumper&lt;/span&gt; 尝试解密 &lt;code&gt;global-metadata.dat&lt;/code&gt; , 但是却失败了&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;/sec-2023/image-20230407124010267.png&#34; alt=&#34;image-20230407124010267&#34; style=&#34;aspect-ratio:1591 / 640;&#34;&gt;&lt;/p&gt;
&lt;p&gt;看了一下 &lt;code&gt;global-metadata.dat&lt;/code&gt;  是没有加密的&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;/sec-2023/image-20230407160715829.png&#34; alt=&#34;image-20230407160715829&#34; style=&#34;aspect-ratio:1920 / 1080;&#34;&gt;&lt;/p&gt;
&lt;p&gt;接下来我们用 ida 反编译 &lt;code&gt;libil2cpp.so&lt;/code&gt; , 发现被加密了&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;/sec-2023/image-20230407142822706.png&#34; alt=&#34;image-20230407142822706&#34; style=&#34;aspect-ratio:1920 / 1080;&#34;&gt;&lt;/p&gt;
&lt;h1 id=&#34;dump解密后的libil2cppso&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#dump解密后的libil2cppso&#34;&gt;#&lt;/a&gt; dump 解密后的 &lt;code&gt;libil2cpp.so&lt;/code&gt;&lt;/h1&gt;
&lt;p&gt;接下来我准备用 frida 来把解密后的 &lt;code&gt;libil2cpp.so&lt;/code&gt;  从内存中 dump 下来&lt;/p&gt;
&lt;p&gt;但是当我用 frida 将代码注入进去后，apk 提示 &lt;code&gt;hack detect&lt;/code&gt; , 然后就退出了&lt;/p&gt;
&lt;p&gt;之后我不用 frida 注入这个 apk, 但是后台依旧运行着 frida-server,apk 依然弹出 &lt;code&gt;hack detect&lt;/code&gt;  后退出&lt;/p&gt;
&lt;p&gt;通过这一点我大致可以判断它的检测方式有这两种可能&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;检测运行的程序名称有没有 &lt;code&gt;frida-server&lt;/code&gt;&lt;/li&gt;
&lt;li&gt;检测 frida-server 的端口&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;我们一个一个去验证一下&lt;/p&gt;
&lt;p&gt;首先我们把后台运行的 frida-server 名称改成 &lt;code&gt;fs&lt;/code&gt;  试试&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;figcaption data-lang=&#34;Bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;blueline:/data/local/tmp &lt;span class=&#34;token comment&#34;&gt;# ./fs&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;修改完后依旧弹出 &lt;code&gt;hack detect&lt;/code&gt;&lt;/p&gt;
&lt;p&gt;那我们再去试一试修改 frida-server 的端口&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;figcaption data-lang=&#34;Bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;blueline:/data/local/tmp &lt;span class=&#34;token comment&#34;&gt;# ./fs -l 0.0.0.0:1234&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;端口修改之后用 frida 注入也不弹窗了&lt;/p&gt;
&lt;p&gt;现在我们可以用 frida 把解密后的 &lt;code&gt;libil2cpp.so&lt;/code&gt; dump 下来，脚本如下&lt;/p&gt;
&lt;figure class=&#34;highlight js&#34;&gt;&lt;figcaption data-lang=&#34;JavaScript&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;function&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;dump_so&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token parameter&#34;&gt;so_name&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    Java&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;perform&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token keyword&#34;&gt;function&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token keyword&#34;&gt;var&lt;/span&gt; currentApplication &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; Java&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;use&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;android.app.ActivityThread&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;currentApplication&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token keyword&#34;&gt;var&lt;/span&gt; dir &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; currentApplication&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;getApplicationContext&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;getFilesDir&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;getPath&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token keyword&#34;&gt;var&lt;/span&gt; libso &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; Process&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;getModuleByName&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;so_name&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        console&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;log&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;[name]:&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; libso&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;name&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        console&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;log&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;[base]:&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; libso&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;base&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        console&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;log&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;[size]:&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;ptr&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;libso&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;size&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;9&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        console&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;log&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;[path]:&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; libso&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;path&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;10&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token keyword&#34;&gt;var&lt;/span&gt; file_path &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; dir &lt;span class=&#34;token operator&#34;&gt;+&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#34;/&#34;&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;+&lt;/span&gt; libso&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;name &lt;span class=&#34;token operator&#34;&gt;+&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#34;_&#34;&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;+&lt;/span&gt; libso&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;base &lt;span class=&#34;token operator&#34;&gt;+&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#34;_&#34;&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;+&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;ptr&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;libso&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;size&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;+&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#34;.so&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;11&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token keyword&#34;&gt;var&lt;/span&gt; file_handle &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;new&lt;/span&gt; &lt;span class=&#34;token class-name&#34;&gt;File&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;file_path&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#34;wb&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;12&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;13&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token keyword&#34;&gt;if&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;file_handle &lt;span class=&#34;token operator&#34;&gt;&amp;amp;&amp;amp;&lt;/span&gt; file_handle &lt;span class=&#34;token operator&#34;&gt;!=&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;null&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;14&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            Memory&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;protect&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;ptr&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;libso&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;base&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; libso&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;size&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#39;rwx&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;15&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            &lt;span class=&#34;token comment&#34;&gt;// 如果报错为 Error: access violation accessing, 那么可以尝试添加下面的这一行代码，libso.base 加上的值是通过 address (access violation accessing)-address (base) 计算出来的&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;16&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            &lt;span class=&#34;token comment&#34;&gt;//Memory.protect(ptr(libso.base.add(0x13b7000)), libso.size-0x13b7000, &#39;rwx&#39;);&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;17&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            &lt;span class=&#34;token keyword&#34;&gt;var&lt;/span&gt; libso_buffer &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;ptr&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;libso&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;base&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;readByteArray&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;libso&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;size&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;18&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            file_handle&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;write&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;libso_buffer&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;19&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            file_handle&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;flush&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;20&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            file_handle&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;close&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;21&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            console&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;log&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;[dump]:&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; file_path&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;22&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;23&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;24&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;25&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;26&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;rpc&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;exports &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;27&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token literal-property property&#34;&gt;dump_so&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;:&lt;/span&gt; dump_so&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;28&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;在使用 frida 运行脚本之前需要注意去做一下&lt;strong&gt;端口转发&lt;/strong&gt;&lt;/p&gt;
&lt;figure class=&#34;highlight powershell&#34;&gt;&lt;figcaption data-lang=&#34;PowerShell&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;adb forward tcp:1234 tcp:1234&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;随后进行 frida 注入&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;figcaption data-lang=&#34;Bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;frida &lt;span class=&#34;token parameter variable&#34;&gt;-H&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;127.0&lt;/span&gt;.0.1:1234 &lt;span class=&#34;token parameter variable&#34;&gt;-l&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#34;D:&lt;span class=&#34;token entity&#34; title=&#34;\f&#34;&gt;\f&lt;/span&gt;rida\sec2023\global-metadata_dump.js&#34;&lt;/span&gt; &lt;span class=&#34;token parameter variable&#34;&gt;-f&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#34;com.com.sec2023.rocketmouse.mouse&#34;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;&lt;img data-src=&#34;/sec-2023/image-20230407160451904.png&#34; alt=&#34;image-20230407160451904&#34; style=&#34;aspect-ratio:1571 / 498;&#34;&gt;&lt;/p&gt;
&lt;h1 id=&#34;再次使用il2cppdumper获取符号信息&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#再次使用il2cppdumper获取符号信息&#34;&gt;#&lt;/a&gt; 再次使用 Il2CppDumper 获取符号信息&lt;/h1&gt;
&lt;p&gt;直接把 dump 下来的 &lt;code&gt;libil2cpp.so&lt;/code&gt;  放到 Il2CppDumper 中，成功获取符号&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;/sec-2023/image-20230407230411862.png&#34; alt=&#34;image-20230407230411862&#34; style=&#34;aspect-ratio:1920 / 497;&#34;&gt;&lt;/p&gt;
&lt;h1 id=&#34;修复dump下来的so&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#修复dump下来的so&#34;&gt;#&lt;/a&gt; 修复 dump 下来的 so&lt;/h1&gt;
&lt;p&gt;对于 dump 下来的 so 文件，所有的段 (segment) 和节 (section) 的偏移都是&lt;strong&gt;在虚拟空间中的偏移&lt;/strong&gt; (即映射到进程空间的虚拟地址偏移), 但静态分析工具分析 so 时所使用的偏移仍然为&lt;strong&gt;在实际文件中的偏移&lt;/strong&gt; (即相对于文件开头的字节偏移量), 错误的偏移导致静态分析工具如 IDA 等无法分析 dump 下来的 so&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;所以我们需要将 &lt;code&gt;segment&lt;/code&gt;  和 &lt;code&gt;section&lt;/code&gt;  在实际文件中的偏移替换为在虚拟空间中的偏移，这些偏移由 &lt;code&gt;program header table&lt;/code&gt;  和 &lt;code&gt;secion header table&lt;/code&gt;  内的成员指出&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;我们将 &lt;code&gt;libil2cpp.so&lt;/code&gt;  和 &lt;code&gt;libil2cpp.so_0x712a997000_0x13cc000.so&lt;/code&gt;  一并拖入 &lt;code&gt;010 editor&lt;/code&gt;  中，两个文件相互对比进行修复&lt;/p&gt;
&lt;p&gt;在 &lt;code&gt;010editor&lt;/code&gt;  中复制一个成员的值到另一个成员中，只需要在软件界面的 &lt;code&gt;Template Results&lt;/code&gt;  中单击想要复制的值按下 &lt;code&gt;Ctrl&lt;/code&gt; + &lt;code&gt;Shift&lt;/code&gt; + &lt;code&gt;C&lt;/code&gt; , 然后单击需要替换的值，按下 &lt;code&gt;Ctrl&lt;/code&gt; + &lt;code&gt;Shift&lt;/code&gt; + &lt;code&gt;V&lt;/code&gt;  即可完成替换&lt;/p&gt;
&lt;h2 id=&#34;修正-段segment-的偏移&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#修正-段segment-的偏移&#34;&gt;#&lt;/a&gt; 修正 段 (segment) 的偏移&lt;/h2&gt;
&lt;blockquote&gt;
&lt;p&gt;段 (segment) 的位置和大小由程序头表 (Program Header Table) 中的这四个成员决定&lt;/p&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;成员名称&lt;/th&gt;
&lt;th&gt;含义&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;p_offset_FROM_FILE_BEGIN&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;在实际文件中的偏移&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;p_vaddr_VIRTUAL_ADDRESS&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;在虚拟空间中的偏移&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;p_filesz_SEGMENT_FILE_LENGTH&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;在实际文件中的大小&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;p_memsz_SEGMENT_RAM_LENGTH&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;在虚拟空间中的大小&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;/blockquote&gt;
&lt;p&gt;在 &lt;code&gt;libil2cpp.so_0x712a997000_0x13cc000.so&lt;/code&gt;  中我们将 &lt;code&gt;program_header_table&lt;/code&gt;  中每一个 &lt;code&gt;element&lt;/code&gt;  的 &lt;code&gt;p_vaddr_VIRTUAL_ADDRESS&lt;/code&gt;  的值复制到 &lt;code&gt;p_offset_FROM_FILE_BEGIN&lt;/code&gt; , &lt;code&gt;p_memsz_SEGMENT_RAM_LENGTH&lt;/code&gt;  的值复制到 &lt;code&gt;p_filesz_SEGMENT_FILE_LENGTH&lt;/code&gt;&lt;/p&gt;
&lt;h2 id=&#34;修正-节头表secion-header-table-的偏移&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#修正-节头表secion-header-table-的偏移&#34;&gt;#&lt;/a&gt; 修正 节头表 (secion header table) 的偏移&lt;/h2&gt;
&lt;blockquote&gt;
&lt;p&gt;节头表 (secion header table) 的位置在&lt;strong&gt;最后一个段 (segment) 之后&lt;/strong&gt;，我们可以从 ELF 文件的 Execution View 直观看出&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;/sec-2023/image-20230901121900113.png&#34; alt=&#34;image-20230901121900113&#34; style=&#34;aspect-ratio:447 / 577;&#34;&gt;&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;由下图所示， &lt;code&gt;libil2cpp.so_0x712a997000_0x13cc000.so&lt;/code&gt;  中 &lt;code&gt;section_header_table&lt;/code&gt;  在实际文件中的偏移为 &lt;code&gt;0x11AB778&lt;/code&gt; , 我们需要将其修改为在虚拟空间中的偏移，这个值为 &lt;code&gt;0x13CB778&lt;/code&gt; , 计算过程如下，此处所涉及计算的成员的值是在 &lt;code&gt;program_header_table&lt;/code&gt;  的最后一个 &lt;code&gt;element&lt;/code&gt; , 即 &lt;code&gt;program_table_entry64_program_table_element[10]&lt;/code&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;section_header_table&lt;/code&gt;  在虚拟空间中的偏移: 0x13CB778 = 0x00000000013BC000 + 0xF778 =  &lt;code&gt;p_vaddr_VIRTUAL_ADDRESS&lt;/code&gt; + &lt;code&gt;p_memsz_SEGMENT_RAM_LENGTH&lt;/code&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;img data-src=&#34;/sec-2023/image-20230901122457467.png&#34; alt=&#34;image-20230901122457467&#34; style=&#34;aspect-ratio:1920 / 1051;&#34;&gt;&lt;/p&gt;
&lt;div class=&#34;note info&#34;&gt;
&lt;p&gt;Section Header Table 和 Program Header Table 并不是一定要位于文件开头和结尾的，其位置由 &lt;code&gt;ELF Header&lt;/code&gt;  指出&lt;/p&gt;
&lt;/div&gt;
&lt;p&gt;决定 &lt;code&gt;section_header_table&lt;/code&gt;  起始地址的成员为 &lt;code&gt;elf_header-&amp;gt;e_shoff_SECTION_HEADER_OFFSET_IN_FILE&lt;/code&gt; , 位置如下图所示，在修改完成后，按下 &lt;code&gt;F5&lt;/code&gt;  重新运行模板 &lt;code&gt;ELF.bt&lt;/code&gt;&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;/sec-2023/image-20230505192823591.png&#34; alt=&#34;image-20230505192823591&#34; style=&#34;aspect-ratio:982 / 899;&#34;&gt;&lt;/p&gt;
&lt;h2 id=&#34;修补section的内容&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#修补section的内容&#34;&gt;#&lt;/a&gt; 修补 section 的内容&lt;/h2&gt;
&lt;blockquote&gt;
&lt;p&gt;在我们修正 节头表 (secion header table) 的偏移后，节头表所在的区域是没有内容的，如下图所示，所以需要从 &lt;code&gt;libil2cpp.so&lt;/code&gt;  中复制节 (section) 的内容到 dump 下来的 so 中&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;/sec-2023/image-20230901122928576.png&#34; alt=&#34;image-20230901122928576&#34; style=&#34;aspect-ratio:1586 / 653;&#34;&gt;&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;我们在 &lt;code&gt;libil2cpp.so&lt;/code&gt;  点击 &lt;code&gt;struct section_header_table&lt;/code&gt;  并按下 &lt;code&gt;Ctrl&lt;/code&gt; + &lt;code&gt;Shift&lt;/code&gt; + &lt;code&gt;C&lt;/code&gt; , 然后回到 &lt;code&gt;libil2cpp.so_0x712a997000_0x13cc000.so&lt;/code&gt;  中，选中 &lt;code&gt;section_header_table&lt;/code&gt;  然后按下 &lt;code&gt;Ctrl&lt;/code&gt; + &lt;code&gt;Shift&lt;/code&gt; + &lt;code&gt;V&lt;/code&gt; , 按下 &lt;code&gt;F5&lt;/code&gt;  重新运行模板 &lt;code&gt;ELF.bt&lt;/code&gt;&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;/sec-2023/image-20230505193356013.png&#34; alt=&#34;image-20230505193356013&#34; style=&#34;aspect-ratio:959 / 1023;&#34;&gt;&lt;/p&gt;
&lt;h2 id=&#34;恢复节section的名称&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#恢复节section的名称&#34;&gt;#&lt;/a&gt; 恢复节 (section) 的名称&lt;/h2&gt;
&lt;p&gt;可以发现修补了节 (section) 的内容之后，section 的名称依旧是乱码&lt;/p&gt;
&lt;p&gt;这是什么原因呢？&lt;/p&gt;
&lt;div class=&#34;note info&#34;&gt;
&lt;p&gt;&lt;code&gt;ELF&lt;/code&gt;  文件中的每个 &lt;code&gt;section&lt;/code&gt;  都是有名字的，比如 &lt;code&gt;.data&lt;/code&gt; 、 &lt;code&gt;.text&lt;/code&gt; 、 &lt;code&gt;.rodata&lt;/code&gt; ，每个名字都是一个字符串，既然是字符串就需要一个字符串池来保存，而这个字符串池也是一个 &lt;code&gt;section&lt;/code&gt; ，或者说准备一个 &lt;code&gt;section&lt;/code&gt;  用来维护一个字符串池，这个字符串池保存了其他 section 以及它自己的名字。这个特殊的 section 叫做 &lt;code&gt;.shstrtab&lt;/code&gt; ，所有 &lt;code&gt;section&lt;/code&gt;  的头部是连续存放在一起的，类似一个数组， &lt;code&gt;e_shstrndx&lt;/code&gt;  变量是 &lt;code&gt;.shstrtab&lt;/code&gt;  在这个数组中的下标。&lt;/p&gt;
&lt;/div&gt;
&lt;p&gt;首先我们要明白 section 的名称是如何通过索引找到的，在 &lt;code&gt;libil2cpp.so_0x712a997000_0x13cc000.so&lt;/code&gt;  中，找到 &lt;code&gt;elf_header-&amp;gt;e_shtrndx_STRING_TABLE_INDEX&lt;/code&gt; , 这个的值为 26 (0x1A), 说明了 &lt;code&gt;section_header_table-&amp;gt;section_table_element[26]&lt;/code&gt;  存储了所有 section 的名称&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;/sec-2023/image-20230505193659902.png&#34; alt=&#34;image-20230505193659902&#34; style=&#34;aspect-ratio:976 / 892;&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;code&gt;section_header_table-&amp;gt;section_table_element[26]&lt;/code&gt;  中 &lt;code&gt;s_offset&lt;/code&gt;  的值决定了 section 的名称将从 &lt;code&gt;1199370h&lt;/code&gt;  去索引&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;/sec-2023/image-20230505195047080.png&#34; alt=&#34;image-20230505195047080&#34; style=&#34;aspect-ratio:954 / 1080;&#34;&gt;&lt;/p&gt;
&lt;p&gt;我们可以在 dump 前后的 &lt;code&gt;libil2cpp.so&lt;/code&gt;  都跳转到这个地址去看看，在 &lt;code&gt;010editor&lt;/code&gt;  中进行地址跳转只需右键该值选择 &lt;code&gt;Goto Address&lt;/code&gt;  即可&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;/sec-2023/image-20230901124209545.png&#34; alt=&#34;image-20230901124209545&#34; style=&#34;aspect-ratio:1273 / 495;&#34;&gt;section 的所有名称都在这个地方&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;/sec-2023/image-20230505195256088.png&#34; alt=&#34;image-20230505195256088&#34; style=&#34;aspect-ratio:1920 / 1080;&#34;&gt;&lt;/p&gt;
&lt;p&gt;之后我们要将 &lt;code&gt;section&lt;/code&gt;  的符号名称从原来的 so 复制到 dump 下来的 so 里面，位置就是我们之前分析出来的 &lt;code&gt;section_table_element[26]&lt;/code&gt;  中 &lt;code&gt;s_offset&lt;/code&gt;  所指向的物理内存地址，即选中 &lt;code&gt;libil2cpp.so&lt;/code&gt;  从 &lt;code&gt;0x1199370h&lt;/code&gt;  到 &lt;code&gt;0x1199470h&lt;/code&gt;  按下 &lt;code&gt;Ctrl&lt;/code&gt; + &lt;code&gt;Shift&lt;/code&gt; + &lt;code&gt;C&lt;/code&gt; , 然后将光标移动到 &lt;code&gt;libil2cpp.so_0x712a997000_0x13cc000.so&lt;/code&gt;  的 &lt;code&gt;119A370h&lt;/code&gt;  处，按下 &lt;code&gt;Ctrl&lt;/code&gt; + &lt;code&gt;Shift&lt;/code&gt; + &lt;code&gt;V&lt;/code&gt;&lt;/p&gt;
&lt;h2 id=&#34;修正-节section-的偏移&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#修正-节section-的偏移&#34;&gt;#&lt;/a&gt; 修正 节 (section) 的偏移&lt;/h2&gt;
&lt;blockquote&gt;
&lt;p&gt;节 (section) 的位置和大小由节头表 (secion_header_table) 中这两个成员决定&lt;/p&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;成员名称&lt;/th&gt;
&lt;th&gt;含义&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;s_addr&lt;/td&gt;
&lt;td&gt;如果此 section 需要映射到进程空间，此成员指定映射的起始地址；如不需映射，此值为 0&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;s_offset&lt;/td&gt;
&lt;td&gt;此 section 相对于文件开头的字节偏移量。如果 section 类型为  &lt;code&gt;SHT_NOBITS&lt;/code&gt; , 表明该 section 在文件中不占空间，这时 sh_offset 没什么用&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;/blockquote&gt;
&lt;p&gt;修正 节 (section) 的偏移有两条规则&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;如果 s_addr 为 0, 无需修改 s_offset&lt;/li&gt;
&lt;li&gt;如果 s_addr 不为 0, 则将 s_addr 的值复制给 s_offset&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;修正完成后，按下 &lt;code&gt;F5&lt;/code&gt;  重新运行模板 &lt;code&gt;ELF.bt&lt;/code&gt; , 可以发现 section 的名称已经恢复，同时也有了 &lt;code&gt;dynamic_symbol_table&lt;/code&gt;&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;/sec-2023/image-20230901125853006.png&#34; alt=&#34;image-20230901125853006&#34; style=&#34;aspect-ratio:1237 / 695;&#34;&gt;&lt;/p&gt;
&lt;h1 id=&#34;在ida中恢复符号&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#在ida中恢复符号&#34;&gt;#&lt;/a&gt; 在 IDA 中恢复符号&lt;/h1&gt;
&lt;p&gt;然后，我们将 &lt;code&gt;libil2cpp.so_0x712a997000_0x13cc000.so&lt;/code&gt;  拖入 &lt;code&gt;IDA&lt;/code&gt;  中进行分析，待分析完成后，点击如图所示的选项重新定位基址为 &lt;code&gt;0x712a997000&lt;/code&gt; , 这样可以分析出更多的符号&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;/sec-2023/image-20230505144017295.png&#34; alt=&#34;image-20230505144017295&#34; style=&#34;aspect-ratio:696 / 654;&#34;&gt;&lt;/p&gt;
&lt;p&gt;之后，我们点击 &lt;code&gt;File-&amp;gt;Script file...&lt;/code&gt;  运行 &lt;code&gt;il2cppdumper&lt;/code&gt;  中的 &lt;code&gt;ida_with_struct_py3.py&lt;/code&gt; , 需要注意的这个脚本需要运行两次，第一次选择 &lt;code&gt;script.json&lt;/code&gt; , 第二次选择 &lt;code&gt;il2cpp.h&lt;/code&gt;&lt;/p&gt;
&lt;p&gt;处理之后的效果如下&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;/sec-2023/image-20230506180743547.png&#34; alt=&#34;image-20230506180743547&#34; style=&#34;aspect-ratio:1920 / 1080;&#34;&gt;&lt;/p&gt;
&lt;h1 id=&#34;寻找ok按钮调用的函数&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#寻找ok按钮调用的函数&#34;&gt;#&lt;/a&gt; 寻找 OK 按钮调用的函数&lt;/h1&gt;
&lt;p&gt;接下来需要知道这个 &lt;code&gt;OK&lt;/code&gt;  按钮调用的函数&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;/sec-2023/screenshot-16808551676034.png&#34; alt=&#34;screenshot&#34; style=&#34;aspect-ratio:1920 / 1200;&#34;&gt;&lt;/p&gt;
&lt;p&gt;我们可以使用这个工具&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9naXRodWIuY29tL0lJSUltbW15eXkvZnJpZGEtaWwyY3BwRHVtcGVy&#34;&gt; frida-il2cppDumper&lt;/span&gt;, 用法就直接用 frida 注入 &lt;code&gt;_agent.js&lt;/code&gt;  就可以了&lt;/p&gt;
&lt;figure class=&#34;highlight powershell&#34;&gt;&lt;figcaption data-lang=&#34;PowerShell&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;frida &lt;span class=&#34;token operator&#34;&gt;-&lt;/span&gt;H 127&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;0&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;0&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;1:1234 &lt;span class=&#34;token operator&#34;&gt;-&lt;/span&gt;l &lt;span class=&#34;token string&#34;&gt;&#34;D:\frida\frida-il2cppDumper-main\_agent.js&#34;&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;-&lt;/span&gt;f &lt;span class=&#34;token string&#34;&gt;&#34;com.com.sec2023.rocketmouse.mouse&#34;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;当我们进入该 apk 之后，下列函数被调用&lt;/p&gt;
