t;/td&gt;&lt;td&gt;&lt;pre&gt;        jmp_addr &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;add_num1 &lt;span class=&#34;token operator&#34;&gt;+&lt;/span&gt; add_num2&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;&amp;amp;&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;0xffffffff&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;210&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        ks &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; Ks&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;KS_ARCH_X86&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; KS_MODE_64&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;211&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        code &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token string-interpolation&#34;&gt;&lt;span class=&#34;token string&#34;&gt;f&#34;jmp &lt;/span&gt;&lt;span class=&#34;token interpolation&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;jmp_addr&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;212&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        patch_call_rax_byte&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; count &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; ks&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;asm&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;code&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; addr&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;mov_rax_qword_xxx_addr &lt;span class=&#34;token operator&#34;&gt;+&lt;/span&gt; &lt;span class=&#34;token builtin&#34;&gt;len&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;movRAX_jmpRAX_patch&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;213&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token comment&#34;&gt;# print(call_func_addr, code, patch_call_rax_byte)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;214&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;215&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        movRAX_jmpRAX_patch &lt;span class=&#34;token operator&#34;&gt;+=&lt;/span&gt; &lt;span class=&#34;token builtin&#34;&gt;bytes&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;patch_call_rax_byte&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;216&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token comment&#34;&gt;# print(movRAX_callRAX_patch)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;217&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        ida_bytes&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;patch_bytes&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;mov_rax_qword_xxx_addr&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;b&#39;\x90&#39;&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;*&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;idc&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;next_head&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;jmp_rax_addr&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;-&lt;/span&gt; mov_rax_qword_xxx_addr&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;218&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        ida_bytes&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;patch_bytes&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;mov_rax_qword_xxx_addr&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; movRAX_jmpRAX_patch&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;219&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token keyword&#34;&gt;print&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string-interpolation&#34;&gt;&lt;span class=&#34;token string&#34;&gt;f&#34;fix jmp rax at &lt;/span&gt;&lt;span class=&#34;token interpolation&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;span class=&#34;token builtin&#34;&gt;hex&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;jmp_rax_addr&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;220&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;221&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    current_addr &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; idc&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;next_head&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;current_addr&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;222&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;223&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;#patch_nop(0x410FB3,0x41142C)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;h1 id=&#34;参考资料&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#参考资料&#34;&gt;#&lt;/a&gt; 参考资料&lt;/h1&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9saW5nemUueHl6L2Jvb2svcmV2ZXJzZS9pZGFfcHl0aG9uLyMlRTUlOUMlQjAlRTUlOUQlODA=&#34;&gt;ida python 使用&lt;/span&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cDovLzE5Mi4xNDQuMjM3LjI5LzIwMjIvMDIvMjMvY29tbW9uL2lkYXB5dGhvbi8=&#34;&gt;idapython 笔记学习&lt;/span&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9ibG9nLmNzZG4ubmV0L3FxXzQ1MzIzOTYwL2FydGljbGUvZGV0YWlscy8xMjU0OTM1ODg=&#34;&gt;在 PyCharm 中写 IDAPython 脚本&lt;/span&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;

 &lt;blockquote&gt;
&lt;p&gt;为了做出腾讯游戏安全竞赛初赛的这道安卓题，开始学习 &lt;code&gt;rwProcMem33 &lt;/code&gt; 的使用来打硬件断点了&lt;/p&gt;
&lt;p&gt;在&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9iYnMua2FueHVlLmNvbS91c2VyLWhvbWUtODMxNTI2Lmh0bQ==&#34;&gt; juice4fun&lt;/span&gt; 师傅做腾讯游戏安全竞赛初赛的安卓题的&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9iYnMua2FueHVlLmNvbS90aHJlYWQtMjc2ODk2Lmh0bSNtc2dfaGVhZGVyX2gyXzI=&#34;&gt; writeup&lt;/span&gt; 时，使用了&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9naXRodWIuY29tL2FiY3ozMTYvcndQcm9jTWVtMzM=&#34;&gt; rwProcMem33&lt;/span&gt; 来对安卓手机打下硬件断点分析反调试，我也对在安卓手机中打硬件断点的工具很感兴趣，所以就学习一下编译和使用的方法啦&lt;/p&gt;
&lt;p&gt;要想使用 rwProcMem33, 编译环境 (即 AOSP 安卓内核源码环境) 的搭建过程是必不可少的，因为最终内核模块是运行在安卓手机的 linux 内核中，而非虚拟机的 linux 内核中，所以内核源码是有必要下载的&lt;/p&gt;
&lt;p&gt;所以这篇文章不仅是硬件断点工具的编译和使用笔记，也是安卓内核的编译笔记，用来记录我在编译内核的过程中遇到的困难，以及如何克服的&lt;/p&gt;
&lt;p&gt;为了更快的下载速度，可以选择配置代理，也可以手动切换下载源，只要不出现网络问题导致下载失败就行&lt;/p&gt;
&lt;p&gt;docker 的使用完全是因为我的虚拟机 shell 环境崩溃，从而导致无法编译，如果对自己虚拟机的 shell 环境足够自信，不使用 docker 也是可以的&lt;/p&gt;
&lt;/blockquote&gt;
&lt;h1 id=&#34;编译环境搭建&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#编译环境搭建&#34;&gt;#&lt;/a&gt; 编译环境搭建&lt;/h1&gt;
&lt;h2 id=&#34;虚拟机配置&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#虚拟机配置&#34;&gt;#&lt;/a&gt; 虚拟机配置&lt;/h2&gt;
&lt;p&gt;我使用的虚拟机为 &lt;code&gt;Ubuntu22.04&lt;/code&gt; , 虚拟机的参考配置如下&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;/rwProcMem33-usage/image-20230811162236189.png&#34; alt=&#34;image-20230811162236189&#34; style=&#34;aspect-ratio:860 / 1002;&#34;&gt;&lt;/p&gt;
&lt;h2 id=&#34;为虚拟机配置代理&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#为虚拟机配置代理&#34;&gt;#&lt;/a&gt; 为虚拟机配置代理&lt;/h2&gt;
&lt;h3 id=&#34;查看虚拟机代理地址&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#查看虚拟机代理地址&#34;&gt;#&lt;/a&gt; 查看虚拟机代理地址&lt;/h3&gt;
&lt;p&gt;打开 &lt;code&gt;clash for windows&lt;/code&gt; , 并打开 &lt;code&gt;Allow LAN&lt;/code&gt;  的开关，随后点击 &lt;code&gt;network interfaces&lt;/code&gt;&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;/rwProcMem33-usage/image-20230811175325211.png&#34; alt=&#34;image-20230811175325211&#34; style=&#34;aspect-ratio:1070 / 760;&#34;&gt;&lt;/p&gt;
&lt;p&gt;请注意我的虚拟机使用的网络连接方式为 NAT 模式，所以需要关注 &lt;code&gt;VMnet8&lt;/code&gt;  的地址，所以对于该虚拟机，代理地址为 &lt;code&gt;192.168.27.1&lt;/code&gt; , 端口就是 &lt;code&gt;clash&lt;/code&gt;  中 &lt;code&gt;Port&lt;/code&gt;  选项所显示的端口&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;/rwProcMem33-usage/image-20230811175516413.png&#34; alt=&#34;image-20230811175516413&#34; style=&#34;aspect-ratio:1070 / 760;&#34;&gt;&lt;/p&gt;
&lt;h3 id=&#34;启用虚拟机代理&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#启用虚拟机代理&#34;&gt;#&lt;/a&gt; 启用虚拟机代理&lt;/h3&gt;
&lt;p&gt;依次点击如下选项进入代理配置&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;/rwProcMem33-usage/image-20230811180538737.png&#34; alt=&#34;image-20230811180538737&#34; style=&#34;aspect-ratio:1278 / 772;&#34;&gt;&lt;/p&gt;
&lt;p&gt;输入代理地址保存即可&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;/rwProcMem33-usage/image-20230811180608202.png&#34; alt=&#34;image-20230811180608202&#34; style=&#34;aspect-ratio:840 / 516;&#34;&gt;&lt;/p&gt;
&lt;h2 id=&#34;配置docker-ubuntu镜像&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#配置docker-ubuntu镜像&#34;&gt;#&lt;/a&gt; 配置 docker ubuntu 镜像&lt;/h2&gt;
&lt;blockquote&gt;
&lt;p&gt;本人因为不小心运行了一个命令 &lt;code&gt;source _setup_env.sh&lt;/code&gt; , 导致虚拟机的 shell 环境整个崩掉了， &lt;code&gt;build.sh&lt;/code&gt;  也屡屡运行失败，看了眼 &lt;code&gt;_setup_env.sh&lt;/code&gt;  我真是只能苦涩的笑…&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;/rwProcMem33-usage/image-20230816224032513.png&#34; alt=&#34;image-20230816224032513&#34; style=&#34;aspect-ratio:884 / 519;&#34;&gt;&lt;/p&gt;
&lt;p&gt;所以不得不用 docker 了，不过用下来发现竟然意外的好用&lt;/p&gt;
&lt;/blockquote&gt;
&lt;h3 id=&#34;安装docker&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#安装docker&#34;&gt;#&lt;/a&gt; 安装 docker&lt;/h3&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;figcaption data-lang=&#34;Bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;sudo&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;apt&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;install&lt;/span&gt; docker.io&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h3 id=&#34;docker-pull代理配置&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#docker-pull代理配置&#34;&gt;#&lt;/a&gt; docker pull 代理配置&lt;/h3&gt;
